CREATE TABLE runtime_profiles (id TEXT NOT NULL, version INTEGER NOT NULL, name TEXT NOT NULL, sandbox_strength TEXT NOT NULL, default_actions_json TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'ACTIVE', PRIMARY KEY(id,version));
